CREATE OR REPLACE FUNCTION calculate_loan_status() 
RETURNS SETOF loan_last
AS $$
BEGIN
    -- Create the temporary table inside the function body
    CREATE TEMPORARY TABLE temp_table (loan_id int, status text);

    -- Insert data into the temporary table
    INSERT INTO temp_table 
    SELECT loan_id, status FROM loan_first WHERE status = 'A'; 

    -- Insert data into the permanent table loan_last
    INSERT INTO loan_last 
    SELECT loan_id, status FROM temp_table; 

    -- Return the data that was inserted into loan_last
    RETURN QUERY SELECT * FROM loan_last;

    -- Optional: Drop the temp table if you want to clean up immediately, 
    -- though it will be dropped automatically at session end.
    -- DROP TABLE temp_table;
END; 
$$ LANGUAGE plpgsql

DROP FUNCTION IF EXISTS update_school_inventory_after_supply() CASCADE;

CREATE OR REPLACE FUNCTION update_school_inventory_after_supply() 
RETURNS TRIGGER 
LANGUAGE plpgsql 
AS $trigger$
BEGIN
    UPDATE school_inventory 
    SET quantity = quantity + NEW.quantity 
    WHERE cdscode = NEW.cdscode 
      AND supply_name = NEW.supply_name;
    RETURN NEW;
END;
$trigger$;

