CREATE PROCEDURE drop_empty_columns()
BEGIN
    DECLARE done INT DEFAULT FALSE;
    DECLARE col_name TEXT;
    DECLARE col_cursor CURSOR FOR 
        SELECT COLUMN_NAME 
        FROM INFORMATION_SCHEMA.COLUMNS 
        WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'digital_localization_analysis';
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;

    -- Temporary variable to hold the dynamic SQL
    DECLARE @check_sql TEXT;
    DECLARE @count_val INT;

    OPEN col_cursor;

    read_loop: LOOP
        FETCH col_cursor INTO col_name;
        IF done THEN
            LEAVE read_loop;
        END IF;

        -- Construct a query to count non-null values in the specific column
        SET @check_sql = CONCAT('SELECT COUNT(*) INTO @count_val FROM digital_localization_analysis WHERE `', col_name, '` IS NOT NULL LIMIT 1');

        -- Prepare and execute the dynamic check
        PREPARE stmt FROM @check_sql;
        EXECUTE stmt;
        DEALLOCATE PREPARE stmt;

        -- If count is 0, the column is empty (all NULLs), so drop it
        IF @count_val = 0 THEN
            SET @drop_sql = CONCAT('ALTER TABLE digital_localization_analysis DROP COLUMN `', col_name, '`');
            PREPARE drop_stmt FROM @drop_sql;
            EXECUTE drop_stmt;
            DEALLOCATE PREPARE drop_stmt;
        END IF;
    END LOOP;

    CLOSE col_cursor;
END //

DELIMITER ;

-- Execute the procedure
CALL drop_empty_columns();

