-- Create a temporary table to track IDs of players that have been processed
CREATE TABLE #ProcessedPlayers (player_id INT PRIMARY KEY);

DECLARE @batch_size INT = 10000;
DECLARE @rows_affected INT = 1;

WHILE @rows_affected > 0
BEGIN
    BEGIN TRANSACTION;

    -- Insert the next batch of players who have not been processed yet
    INSERT INTO player_stats (player_id, match_id, goals, assists, yellow_cards, red_cards, minutes_played)
    SELECT TOP (@batch_size) 
        t.player_id, t.match_id, t.goals, t.assists, t.yellow_cards, t.red_cards, t.minutes_played
    FROM player_stats_temp t
    WHERE NOT EXISTS (
        SELECT 1 
        FROM #ProcessedPlayers p 
        WHERE p.player_id = t.player_id
    );

    -- Capture the number of rows inserted in this batch
    SET @rows_affected = @@ROWCOUNT;

    -- Record the IDs of the players inserted in this batch
    INSERT INTO #ProcessedPlayers (player_id)
    SELECT player_id 
    FROM player_stats_temp t
    WHERE NOT EXISTS (
        SELECT 1 
        FROM #ProcessedPlayers p 
        WHERE p.player_id = t.player_id
    );

    COMMIT TRANSACTION;
END

-- Clean up the tracking table
DROP TABLE #ProcessedPlayers

