-- Create a reusable function to split the comma-separated string
CREATE FUNCTION [dbo].[SplitString]
(
    @String NVARCHAR(MAX),
    @Delimiter NVARCHAR(1)
)
RETURNS TABLE
AS
RETURN
(
    SELECT 
        CAST([Value] AS FLOAT) AS Value, -- Cast to FLOAT to handle decimal precision
        ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS ItemIndex
    FROM 
        STRING_SPLIT(@String, @Delimiter)
);
GO

-- Example Usage:
DECLARE @InputString NVARCHAR(MAX) = '1.25,5.34,6.9';

-- Parse the values into a table variable (handles variable number of items)
DECLARE @ParsedValues TABLE (ItemIndex INT, Value FLOAT);

