SELECT @Var1 = Value FROM @ParsedValues WHERE ItemIndex = 1;
SELECT @Var2 = Value FROM @ParsedValues WHERE ItemIndex = 2;
SELECT @Var3 = Value FROM @ParsedValues WHERE ItemIndex = 3;

